187	
188	    it.todo(
189	      "should base cap on unmodified insurance value — cursed sword: value 1000 G, cap 2000 G"
190	    );
191	
192	    it.todo(
193	      "should compute insurance sum including components at 250 G each — sword + 3 runes: sum 1750 G (block discount affects premium only)"
194	    );
195	  });
196	
197	  // ── Claim: cap exhaustion across successive claims ──────────────────
198	  describe("Claim - cap exhaustion", () => {
199	    it.todo(
